题目传送门
简要题意给定一个长度为  的只由数字  到  组成的字符串  ，求  中有多少个子串满足 所有数字出现次数的最大值小于等于出现的不同数字的数量 ，其中  。
分析题目拿到手，先想暴力解法。我们可以直接枚举  的所有子串，并统计子串中数字  出现的次数（记为  ），以及子串中出现的数字个数（记为  ）。再记  ，比较  并记录答案即可。
for(int i=1;i&lt;=n;i++){	memset(cnt,0,sizeof(cnt));	maxn=0;	sum=0;	for(int j=i;j&lt;=n;j++){		int pos=a[j];		if(!cnt[pos]) sum++;		cnt[pos]++;		maxn=max(maxn,cnt[pos])		if(sum&gt;=maxn) ans++;	}}
显然，这种  的时间复杂度是过不去  的。所以我们考虑优化。
优化显然，所有的数字个数不会超过  ，所以  ，而  ，所以可以得知符合条件的子串的长度一定不会大于  （每个数字各出现  次）。所以，我们可以将
for(ll j=i;j&lt;=n;j++)
改成
for(ll j=0;j+i&lt;=n&amp;&amp;j&lt;=100;j++)
这样就可以将我们的时间复杂度优化到  ，轻松  。
完整代码#include&lt;bits/stdc++.h&gt;#define ll long long#define ma 214514using namespace std;ll read(){	char ch=getchar();	ll x=0,f=1;	while('0'&gt;ch||ch&gt;'9'){		if(ch=='-') f=-1;		ch=getchar();	}	while('0'&lt;=ch&amp;&amp;ch&lt;='9'){		x=x*10+ch-'0';		ch=getchar();	}	return x*f;}ll t;ll n;ll cnt[10];ll maxn;ll a[ma];ll ans=0;ll sum=0;char x;int main(){	t=read();	while(t--){		n=read();		memset(cnt,0,sizeof(cnt));		ans=0,sum=0;		for(ll i=1;i&lt;=n;i++){			x=getchar();			a[i]=x-'0';//读入时转化成字符读入，防止读入一长串数字		}		for(ll i=1;i&lt;=n;i++){			memset(cnt,0,sizeof(cnt));			maxn=0;			sum=0;			for(ll j=0;j+i&lt;=n&amp;&amp;j&lt;=100;j++){				ll pos=a[j+i];				if(!cnt[pos]) sum++;				cnt[pos]++;				maxn=max(maxn,cnt[pos]);				if(sum&gt;=maxn) ans++;			}		}		printf("%lld\n",ans);	}	return 0;}

 题目传送门
   一道耗费了本蒟蒻与某机房卷王半天的恶心题 
题目描述给定一个图，求每个 X 连通块之间的最短 Hamilton 路径。假如您不知道 Hamilton 路径是什么
分析这题本质上是 Hamilton 路径的模板题，但是难就难在题目并没有直接将一个抽象过的无向图给你，而是给了一个具体的地图。那么我们第一步就应该将这个地图抽象成一个无向图。
First首先我们来找连通块。记  为坐标为  的 X 所属的连通块，  为连通块的总数， 为我们存的地图（将 S 存为 ，X 存为 ，. 存为 - ）。则我们可以用 DFS 来求连通块 （我是不会说我不会 BFS 的）ll dx[4]={0,1,0,-1};ll dy[4]={1,0,-1,0};ll belong[ma][ma],tot=0;ll mp[ma][ma];void dfs1(ll x,ll y){	if(x&gt;n||y&gt;m||x&lt;1||y&lt;1) return;//到边界停止	if(mp[x][y]!=0||belong[x][y]) return;//找过了或不是陆地就不找了	if(mp[x][y]==0){		belong[x][y]=tot;//记录连通块	}	for(ll i=0;i&lt;4;i++){		ll xx=x+dx[i],yy=y+dy[i];//位移深搜		dfs1(xx,yy);	}}
Second找完了联通块，就开始建图了。我们记  为联通块  到  的最短路径。那么我们要如何求这个最短路径呢？类比双端队列优化的 SPFA，我们用一个双端队列对每一个连通块都跑一遍 BFS，记  为当前连通块到  的最短路径，再去用  的最小值更新  即可。
deque&lt;pair&lt;ll,ll&gt;&gt; q;ll dis[ma][ma];ll w[16][16];void bfs(){	while(q.size()){		ll x=q.front().first,y=q.front().second;		q.pop_front();		for(ll i=0;i&lt;4;i++){			ll xx=x+dx[i],yy=y+dy[i];			if(xx&gt;n||yy&gt;m||xx&lt;1||yy&lt;1) continue;//越界			if(dis[xx][yy]||mp[xx][yy]==-1) continue;//访问过			//如果是 'X' ，则推到队首，距离不变			if(mp[xx][yy]==0){				dis[xx][yy]=dis[x][y];				q.push_front(make_pair(xx,yy));			}			//如果是 'S' ，则推到队尾，距离加1			else if(mp[xx][yy]==1){				dis[xx][yy]=dis[x][y]+1;				q.push_back(make_pair(xx,yy));			}		}	}}//in main()memset(w,0x3f,sizeof(w));for(ll i=1;i&lt;=tot;i++){	memset(dis,0,sizeof(dis));	for(ll j=1;j&lt;=n;j++){		for(ll k=1;k&lt;=m;k++){			if(belong[j][k]==i){				//如果(j,k)属于第i个连通块，则推到队首				q.push_front(make_pair(j,k));				dis[j][k]=1;//小技巧:为了防止0在 BFS 时一直不被更新，初始便设置为1。			}		}	}	bfs();	for(ll j=1;j&lt;=n;j++){		for(ll k=1;k&lt;=m;k++){			//(j,k)为枚举的点			for(ll cx=1;cx&lt;=n;cx++){				for(ll cy=1;cy&lt;=m;cy++){					//(cx,cy)为属于第i个连通块的点					if(belong[j][k]&amp;&amp;belong[cx][cy]&amp;&amp;belong[cx][cy]==i){						w[i][belong[j][k]]=min(w[i][belong[j][k]],dis[j][k]-dis[cx][cy]);//更新w					}				}			}		}	}}
Final现在，我们总算将这题最最 恶心 难的地方处理完啦，接下来便是纯纯的 最短 Hamilton 路径 板子。但是注意我们是可以随便选起点的，所以要对每一个点作为起点都跑一遍状压 DP，求出最小的答案即可。
状压 DP 具体见这题
ll dp[16][1&lt;&lt;16];memset(dp,0x3f,sizeof(dp));for(ll i=1;i&lt;=tot;i++) dp[i][1&lt;&lt;(i-1)]=0;for(ll i=1;i&lt;=tot;i++){	for(ll j=1&lt;&lt;(i-1)+1;j&lt;1&lt;&lt;tot;j++){		for(ll k=1;k&lt;=tot;k++){			if((j&gt;&gt;(k-1))&amp;1){				for(ll l=1;l&lt;=tot;l++){					if((j^1&lt;&lt;(k-1))&gt;&gt;(l-1)&amp;1){						dp[k][j]=min(dp[k][j],dp[l][j^1&lt;&lt;(k-1)]+w[l][k]);					}				}			}		}	}}ll ans=inf;for(ll i=1;i&lt;=tot;i++) ans=min(ans,dp[i][(1&lt;&lt;tot)-1]);
完整代码#include&lt;bits/stdc++.h&gt;#define ll long long#define ma 100#define mod 1000000007#define il inlineusing namespace std;const ll inf=1e18+10;ll read(){	char ch=getchar();	ll x=0,f=1;	while(ch&gt;'9'||ch&lt;'0'){	if(ch=='-') f=-1;	ch=getchar();	}	while('0'&lt;=ch&amp;&amp;ch&lt;='9'){	x=x*10+ch-'0';	ch=getchar();	}	return x*f;}ll n,m;ll mp[ma][ma];ll dx[4]={0,1,0,-1};ll dy[4]={1,0,-1,0};ll dp[16][1&lt;&lt;16];ll w[16][16];ll belong[ma][ma],tot=0;deque&lt;pair&lt;ll,ll&gt;&gt; q;ll dis[ma][ma];void dfs1(ll x,ll y){	if(x&gt;n||y&gt;m||x&lt;1||y&lt;1) return;	if(mp[x][y]!=0||belong[x][y]) return;	if(mp[x][y]==0){		belong[x][y]=tot;	}	for(ll i=0;i&lt;4;i++){		ll xx=x+dx[i],yy=y+dy[i];		dfs1(xx,yy);	}}void bfs(){	while(q.size()){		ll x=q.front().first,y=q.front().second;		q.pop_front();		for(ll i=0;i&lt;4;i++){			ll xx=x+dx[i],yy=y+dy[i];			if(xx&gt;n||yy&gt;m||xx&lt;1||yy&lt;1) continue;			if(dis[xx][yy]||mp[xx][yy]==-1) continue;			if(mp[xx][yy]==0){				dis[xx][yy]=dis[x][y];				q.push_front(make_pair(xx,yy));			}			else if(mp[xx][yy]==1){				dis[xx][yy]=dis[x][y]+1;				q.push_back(make_pair(xx,yy));			}		}	}}int main(){	n=read(),m=read();	for(ll i=1;i&lt;=n;i++){		char x[100];		cin&gt;&gt;x+1;		for(ll j=1;j&lt;=m;j++){			if(x[j]=='.') mp[i][j]=-1;			if(x[j]=='X') mp[i][j]=0;			if(x[j]=='S') mp[i][j]=1;		}	}	for(ll i=1;i&lt;=n;i++){		for(ll j=1;j&lt;=m;j++){			if(!belong[i][j]&amp;&amp;!mp[i][j]){				++tot;				dfs1(i,j);			}		}	}	memset(w,0x3f,sizeof(w));	for(ll i=1;i&lt;=tot;i++){		memset(dis,0,sizeof(dis));		for(ll j=1;j&lt;=n;j++){			for(ll k=1;k&lt;=m;k++){				if(belong[j][k]==i){					q.push_front(make_pair(j,k));					dis[j][k]=1;				}			}		}		bfs();		for(ll j=1;j&lt;=n;j++){			for(ll k=1;k&lt;=m;k++){				for(ll cx=1;cx&lt;=n;cx++){					for(ll cy=1;cy&lt;=m;cy++){						if(belong[j][k]&amp;&amp;belong[cx][cy]&amp;&amp;belong[cx][cy]==i){							w[i][belong[j][k]]=min(w[i][belong[j][k]],dis[j][k]-dis[cx][cy]);						}					}				}			}		}	}	memset(dp,0x3f,sizeof(dp));	for(ll i=1;i&lt;=tot;i++) dp[i][1&lt;&lt;(i-1)]=0;	for(ll i=1;i&lt;=tot;i++){		for(ll j=1&lt;&lt;(i-1)+1;j&lt;1&lt;&lt;tot;j++){			for(ll k=1;k&lt;=tot;k++){				if((j&gt;&gt;(k-1))&amp;1){					for(ll l=1;l&lt;=tot;l++){						if((j^1&lt;&lt;(k-1))&gt;&gt;(l-1)&amp;1){							dp[k][j]=min(dp[k][j],dp[l][j^1&lt;&lt;(k-1)]+w[l][k]);						}					}				}			}		}	}	ll ans=inf;	for(ll i=1;i&lt;=tot;i++) ans=min(ans,dp[i][(1&lt;&lt;tot)-1]);	printf("%lld\n",ans);	return 0;}
